+static double lerp(double a, double b, double t) noexcept
+{
+    if ((a <= 0 && b >= 0) || (a >= 0 && b <= 0)) return t * b + (1 - t) * a;
+
+    if (t == 1) return b;
+    const double x = a + t * (b - a);
+    if (t > 1 == b > a)
+        return b < x ? x : b;
+    else
+        return x < b ? x : b;
+}
