+      std::cout << "Benchmark results min/avg/max " << *min << "/" << avg << "/"
+                << *max << "  ms" << std::endl;
+      break;
+  }
+  case test_mode::COMPRESSION_FACTOR:
+      if (!quiet) {
+          std::cout << "For " << value_count << " values in the range [" << min_value << ", " << max_value
